   1→import React, { useState, useMemo, useCallback, useEffect, useRef, lazy, Suspense, createContext, useContext } from 'react';
   2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
   3→import { analyzeUrl } from './services/analyzer';
   4→import { db } from './services/database';
   5→import Home from './pages/Home';
   6→import Login from './pages/Login';
   7→import Analyze from './pages/Analyze';
   8→
   9→// Lazy-loaded pages for bundle optimization
  10→const Dashboard = lazy(() => import('./pages/Dashboard'));
  11→const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
  12→const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
  13→const HistoryView = lazy(() => import('./pages/History'));
  14→const SMCStudio = lazy(() => import('./pages/SMCStudio'));
  15→const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
  16→const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
  17→const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
  18→const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
  19→const Directory = lazy(() => import('./pages/Directory'));
  20→const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
  21→const Recharge = lazy(() => import('./pages/Recharge'));
  22→const Projects = lazy(() => import('./pages/Projects'));
  23→const Account = lazy(() => import('./pages/Account'));
  24→const Clients = lazy(() => import('./pages/Clients'));
  25→const Affiliation = lazy(() => import('./pages/Affiliation'));
  26→const ContentWriter = lazy(() => import('./pages/ContentWriter'));
  27→const Reputation = lazy(() => import('./pages/Reputation'));
  28→const BotTracking = lazy(() => import('./pages/BotTracking'));
  29→const Messages = lazy(() => import('./pages/Messages'));
  30→const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
  31→const MissionOrders = lazy(() => import('./pages/MissionOrders'));
  32→const BlogOptimizer = lazy(() => import('./pages/BlogOptimizer'));
  33→import {
  34→  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
  35→  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
  36→  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
  37→  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
  38→  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X,
  39→  Search, Activity, BookOpen, UserCircle, AlertTriangle, AlertCircle, Info, CheckCircle
  40→} from 'lucide-react';
  41→import { I18nProvider, useTranslation, LanguageSelector } from './i18n';
  42→
  43→// ── Toast Notification System ──
  44→interface Toast {
  45→  id: string;
  46→  type: 'success' | 'error' | 'info';
  47→  message: string;
  48→}
  49→
  50→const ToastContext = createContext<{
  51→  showToast: (type: Toast['type'], message: string) => void;
  52→}>({ showToast: () => {} });
  53→
  54→export const useToast = () => useContext(ToastContext);
  55→
  56→const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
  57→  return (
  58→    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-2.5 pointer-events-none">
  59→      {toasts.map((toast) => {
  60→        const styles = {
  61→          success: 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300',
  62→          error: 'bg-red-500/15 border-red-500/30 text-red-300',
  63→          info: 'bg-blue-500/15 border-blue-500/30 text-blue-300',
  64→        };
  65→        const icons = { success: '✓', error: '✕', info: 'ℹ' };
  66→        return (
  67→          <div
  68→            key={toast.id}
  69→            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-2xl shadow-black/40 animate-in slide-in-from-right fade-in duration-300 ${styles[toast.type]}`}
  70→            onClick={() => onRemove(toast.id)}
  71→          >
  72→            <span className="text-sm font-bold">{icons[toast.type]}</span>
  73→            <span className="text-sm font-medium">{toast.message}</span>
  74→          </div>
  75→        );
  76→      })}
  77→    </div>
  78→  );
  79→};
  80→
  81→// Command Palette Panel component
  82→const CommandPalettePanel: React.FC<{ onClose: () => void; onNavigate: (view: string) => void }> = ({ onClose, onNavigate }) => {
  83→  const [query, setQuery] = useState('');
  84→  const inputRef = useRef<HTMLInputElement>(null);
  85→
  86→  useEffect(() => {
  87→    setTimeout(() => inputRef.current?.focus(), 100);
  88→  }, []);
  89→
  90→  const commands = [
  91→    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '🔍', category: 'Navigation' },
  92→    { id: 'dashboard', label: 'Dashboard Pro', icon: '📊', category: 'Navigation' },
  93→    { id: 'projects', label: 'Monitoring AEO', icon: '📈', category: 'Navigation' },
  94→    { id: 'generative-tools', label: 'Outils Génératifs', icon: '✨', category: 'Outils' },
  95→    { id: 'smc-studio', label: 'SMC Studio', icon: '✏️', category: 'Outils' },
  96→    { id: 'content-writer', label: 'AI Content Writer', icon: '📝', category: 'Outils' },
  97→    { id: 'reputation', label: 'Réputation IA', icon: '🛡️', category: 'Outils' },
  98→    { id: 'source-of-truth', label: 'Source of Truth', icon: '📄', category: 'Outils' },
  99→    { id: 'schema-org', label: 'Schema.org Generator', icon: '🔧', category: 'Outils' },
 100→    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '🤖', category: 'Outils' },
 101→    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '👁️', category: 'Outils' },
 102→    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '📰', category: 'Outils' },
 103→    { id: 'directory', label: 'Annuaire Indexé', icon: '📚', category: 'Navigation' },
 104→    { id: 'recharge', label: 'GTO Gas Station', icon: '⛽', category: 'Navigation' },
 105→    { id: 'clients', label: 'Base Clients', icon: '👥', category: 'Navigation' },
 106→    { id: 'mission-orders', label: 'Ordres de Mission', icon: '📋', category: 'Navigation' },
 107→    { id: 'alerts', label: 'Alertes AEO', icon: '🔔', category: 'Navigation' },
 108→    { id: 'account', label: 'Compte & Plan', icon: '👤', category: 'Navigation' },
 109→    { id: 'affiliation', label: 'Programme Partenaire', icon: '🤝', category: 'Navigation' },
 110→  ];
 111→
 112→  const filtered = query
 113→    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
 114→    : commands;
 115→
 116→  const grouped = filtered.reduce((acc, cmd) => {
 117→    if (!acc[cmd.category]) acc[cmd.category] = [];
 118→    acc[cmd.category].push(cmd);
 119→    return acc;
 120→  }, {} as Record<string, typeof commands>);
 121→
 122→  return (
 123→    <div
 124→      className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden"
 125→      onClick={(e) => e.stopPropagation()}
 126→    >
 127→      <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
 128→        <Search size={18} className="text-gray-500 shrink-0" />
 129→        <input
 130→          ref={inputRef}
 131→          type="text"
 132→          value={query}
 133→          onChange={(e) => setQuery(e.target.value)}
 134→          placeholder="Rechercher une page, un outil..."
 135→          className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
 136→        />
 137→        <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">ESC</kbd>
 138→      </div>
 139→      <div className="max-h-[340px] overflow-y-auto py-2">
 140→        {Object.keys(grouped).length === 0 ? (
 141→          <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun résultat pour &ldquo;{query}&rdquo;</div>
 142→        ) : (
 143→          Object.entries(grouped).map(([category, cmds]) => (
 144→            <div key={category}>
 145→              <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
 146→              {cmds.map((cmd) => (
 147→                <button
 148→                  key={cmd.id}
 149→                  onClick={() => onNavigate(cmd.id)}
 150→                  className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
 151→                >
 152→                  <span className="text-base">{cmd.icon}</span>
 153→                  <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{cmd.label}</span>
 154→                </button>
 155→              ))}
 156→            </div>
 157→          ))
 158→        )}
 159→      </div>
 160→      <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
 161→        <div className="flex items-center gap-3">
 162→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">↑↓</kbd> naviguer</span>
 163→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">↵</kbd> ouvrir</span>
 164→        </div>
 165→        <span>CitedBy.ai</span>
 166→      </div>
 167→    </div>
 168→  );
 169→};
 170→
 171→const PLAN_LIMITS = {
 172→  free: 1,
 173→  pro: 3,
 174→  enterprise: 1000 // Illimité en pratique
 175→};
 176→
 177→const App: React.FC = () => {
 178→  return (
 179→    <I18nProvider>
 180→      <AppContent />
 181→    </I18nProvider>
 182→  );
 183→};
 184→
 185→const AppContent: React.FC = () => {
 186→  const { t, tf, locale } = useTranslation();
 187→
 188→  // ── Toast system ──
 189→  const [toasts, setToasts] = useState<Toast[]>([]);
 190→  const showToast = useCallback((type: Toast['type'], message: string) => {
 191→    const id = Date.now().toString();
 192→    setToasts(prev => [...prev, { id, type, message }]);
 193→    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
 194→  }, []);
 195→  const removeToast = useCallback((id: string) => {
 196→    setToasts(prev => prev.filter(t => t.id !== id));
 197→  }, []);
 198→
 199→  // ── Profile dropdown ──
 200→  const [isProfileOpen, setIsProfileOpen] = useState(false);
 201→  const profileRef = useRef<HTMLDivElement>(null);
 202→  useEffect(() => {
 203→    const handleClickOutside = (e: MouseEvent) => {
 204→      if (profileRef.current && !profileRef.current.contains(e.target as Node)) setIsProfileOpen(false);
 205→    };
 206→    if (isProfileOpen) document.addEventListener('mousedown', handleClickOutside);
 207→    return () => document.removeEventListener('mousedown', handleClickOutside);
 208→  }, [isProfileOpen]);
 209→
 210→  // ── Page transition ──
 211→  const [pageKey, setPageKey] = useState(0);
 212→
 213→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders' | 'blog-optimizer'>('home');
 214→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 215→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 216→  
 217→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 218→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 219→  
 220→  // Load history from DB on mount
 221→  useEffect(() => {
 222→    const loadedHistory = db.getAll();
 223→    setHistory(loadedHistory);
 224→  }, []);
 225→
 226→  // Bibliothèques de contenu généré
 227→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 228→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 229→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 230→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 231→
 232→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 233→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
 234→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
 235→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
 236→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
 237→  
 238→  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
 239→  const [sectionsState, setSectionsState] = useState({
 240→    optimization: false,
 241→    tools: false
 242→  });
 243→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
 244→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
 245→  const [isNotifOpen, setIsNotifOpen] = useState(false);
 246→  const notifRef = useRef<HTMLDivElement>(null);
 247→
 248→  // Mock notifications data
 249→  const notifications = [
 250→    { id: 1, type: 'critical' as const, title: 'Chute de visibilité détectée sur votre site principal', time: 'Il y a 12min', unread: true },
 251→    { id: 2, type: 'warning' as const, title: 'Votre quota GTO Gas est bientôt épuisé (15% restant)', time: 'Il y a 2h', unread: true },
 252→    { id: 3, type: 'info' as const, title: 'Nouveau rapport de monitoring AEO disponible', time: 'Il y a 5h', unread: true },
 253→    { id: 4, type: 'success' as const, title: 'Audit SEO terminé avec succès pour example.com', time: 'Il y a 1j', unread: false },
 254→    { id: 5, type: 'warning' as const, title: 'Mise à jour des critères de référencement Google détectée', time: 'Il y a 2j', unread: false },
 255→  ];
 256→  const unreadCount = notifications.filter(n => n.unread).length;
 257→
 258→  // Close notification panel when clicking outside
 259→  useEffect(() => {
 260→    const handleClickOutside = (event: MouseEvent) => {
 261→      if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
 262→        setIsNotifOpen(false);
 263→      }
 264→    };
 265→    if (isNotifOpen) {
 266→      document.addEventListener('mousedown', handleClickOutside);
 267→    }
 268→    return () => {
 269→      document.removeEventListener('mousedown', handleClickOutside);
 270→    };
 271→  }, [isNotifOpen]);
 272→
 273→  // Command Palette (Ctrl+K)
 274→  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
 275→  useEffect(() => {
 276→    const handleKeyDown = (e: KeyboardEvent) => {
 277→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
 278→        e.preventDefault();
 279→        setIsCommandPaletteOpen(prev => !prev);
 280→      }
 281→      if (e.key === 'Escape') {
 282→        setIsCommandPaletteOpen(false);
 283→      }
 284→    };
 285→    document.addEventListener('keydown', handleKeyDown);
 286→    return () => document.removeEventListener('keydown', handleKeyDown);
 287→  }, []);
 288→
 289→  // Default user is NULL to allow testing the login flow
 290→  const [user, setUser] = useState<User | null>(null);
 291→
 292→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 293→  const monthlyProjectCount = useMemo(() => {
 294→    if (history.length === 0) return 0;
 295→
 296→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 297→    const now = new Date();
 298→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 299→
 300→    // 1. Identifier la date de création (première analyse) de chaque domaine
 301→    const projectCreationDates = new Map<string, Date>();
 302→    
 303→    history.forEach(h => {
 304→        let hostname;
 305→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 306→        
 307→        const analysisDate = new Date(h.timestamp);
 308→        
 309→        if (!projectCreationDates.has(hostname)) {
 310→            projectCreationDates.set(hostname, analysisDate);
 311→        } else {
 312→            // On garde la date la plus ancienne trouvée pour ce domaine
 313→            if (analysisDate < projectCreationDates.get(hostname)!) {
 314→                projectCreationDates.set(hostname, analysisDate);
 315→            }
 316→        }
 317→    });
 318→
 319→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 320→    let count = 0;
 321→    projectCreationDates.forEach((creationDate) => {
 322→        if (creationDate >= billingCycleStart) {
 323→            count++;
 324→        }
 325→    });
 326→    
 327→    return count;
 328→  }, [history]);
 329→
 330→  // Vérifier si le plan d'action est complet (toutes les recommendations ont une solution générée)
 331→  const actionPlanStatus = useMemo(() => {
 332→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
 333→    const latest = history[history.length - 1];
 334→    const total = latest.recommendations.length;
 335→    const completed = latest.recommendations.filter(rec =>
 336→      latest.generatedSolutions?.[rec.id]
 337→    ).length;
 338→    return { complete: total > 0 && completed === total, completed, total };
 339→  }, [history]);
 340→
 341→  const navigateTo = (view: typeof currentView) => {
 342→    setIsMobileMenuOpen(false);
 343→    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
 344→    if (view !== 'recharge') {
 345→        setInitialRechargePackId(null);
 346→    }
 347→    // Reset l'onglet du compte si on ne va pas vers le compte
 348→    if (view !== 'account') {
 349→        setInitialAccountTab('profile');
 350→    }
 351→    setViewHistory(prev => [...prev, currentView]);
 352→    setCurrentView(view);
 353→    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
 354→    setPageKey(prev => prev + 1);
 355→  };
 356→
 357→  const goBack = () => {
 358→    setIsMobileMenuOpen(false);
 359→    if (viewHistory.length > 0) {
 360→      const newHistory = [...viewHistory];
 361→      const prevView = newHistory.pop();
 362→      setViewHistory(newHistory);
 363→      if (prevView) {
 364→        setCurrentView(prevView as any);
 365→        setRefreshKey(prev => prev + 1);
 366→      }
 367→    } else {
 368→      setCurrentView('home'); // Default fallback
 369→      setRefreshKey(prev => prev + 1);
 370→    }
 371→  };
 372→
 373→  const toggleSection = (section: keyof typeof sectionsState) => {
 374→    setSectionsState(prev => {
 375→      const isAlreadyOpen = prev[section];
 376→      return {
 377→        optimization: false,
 378→        tools: false,
 379→        [section]: !isAlreadyOpen
 380→      };
 381→    });
 382→  };
 383→
 384→  const handleHomeClick = () => {
 385→    navigateTo('home');
 386→    setSectionsState({
 387→      optimization: false,
 388→      tools: false
 389→    });
 390→  };
 391→
 392→  const handleDashboardClick = () => {
 393→    navigateTo('dashboard');
 394→    setSectionsState({
 395→      optimization: false,
 396→      tools: false
 397→    });
 398→  };
 399→
 400→  const handleRechargeClick = () => {
 401→    navigateTo('recharge');
 402→    setSectionsState({
 403→      optimization: false,
 404→      tools: false
 405→    });
 406→  };
 407→
 408→  const handleDirectRecharge = (packId: number) => {
 409→    setInitialRechargePackId(packId);
 410→    navigateTo('recharge');
 411→  };
 412→
 413→  const handleAnalyze = async (url: string) => {
 414→    // Vérification de la limite de projets (Quota mensuel)
 415→    if (user) {
 416→        const limit = PLAN_LIMITS[user.plan] || 1;
 417→        let hostname = url;
 418→        try { hostname = new URL(url).hostname; } catch(e) {}
 419→
 420→        // On vérifie si c'est un projet déjà existant dans l'historique global
 421→        const isExistingProject = history.some(h => {
 422→            try { return new URL(h.url).hostname === hostname; } 
 423→            catch(e) { return false; }
 424→        });
 425→
 426→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
 427→        // Les anciens projets ne comptent pas dans cette limite
 428→        if (!isExistingProject && monthlyProjectCount >= limit) {
 429→            // Redirection vers l'onglet Abonnement
 430→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
 431→            setInitialAccountTab('subscription');
 432→            navigateTo('account');
 433→            return;
 434→        }
 435→    }
 436→
 437→    setIsAnalyzing(true);
 438→    try {
 439→      const result = await analyzeUrl(url);
 440→      setAnalysisData(result);
 441→      
 442→      // Update history via DB service
 443→      const updatedHistory = db.add(result);
 444→      setHistory(updatedHistory);
 445→      
 446→      // Redirection vers Monitoring AEO → onglet Rapport d'Audit
 447→      setResultsTab('details');
 448→      navigateTo('projects');
 449→      setSectionsState({
 450→        optimization: false,
 451→        tools: false
 452→      });
 453→    } catch (error) {
 454→      console.error("Analysis failed", error);
 455→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
 456→    } finally {
 457→      setIsAnalyzing(false);
 458→    }
 459→  };
 460→
 461→  // Used for Admin/User private analysis view
 462→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
 463→    setAnalysisData(result);
 464→    setResultsTab(tab);
 465→    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
 466→    navigateTo('projects');
 467→    setSectionsState({
 468→        optimization: true,
 469→        tools: false
 470→    });
 471→  };
 472→
 473→  // New handler for Public Directory View
 474→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
 475→    setAnalysisData(result);
 476→    navigateTo('directory-entity');
 477→  };
 478→
 479→  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
 480→    if (analysisData) {
 481→      setResultsTab(tab);
 482→      navigateTo('results');
 483→    } else if (history.length > 0) {
 484→      handleViewAnalysis(history[0], tab);
 485→    } else {
 486→      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
 487→      navigateTo('analyze');
 488→    }
 489→  };
 490→
 491→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
 492→    const updatedHistory = db.update(index, updatedData);
 493→    setHistory(updatedHistory);
 494→  };
 495→
 496→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
 497→    const timestamp = new Date().toISOString();
 498→    const solutionWithMeta = { ...solution, timestamp };
 499→
 500→    setAnalysisData(prev => {
 501→        if (!prev || prev.timestamp !== analysisId) return prev;
 502→        
 503→        return {
 504→            ...prev,
 505→            generatedSolutions: {
